window.ERAS = [{"key":"ragtime","name":"Ragtime / 前爵士","years":"1890s–1910s","keywords":"切分节奏 · 钢琴 · 进行曲","desc":"爵士乐的源头。拉格泰姆把进行曲的左手节奏与切分的右手旋律结合，在钢琴上预演了后来摇摆的脉搏。它还不是即兴的音乐，却第一次让黑人音乐语言走进美国客厅。"},{"key":"neworleans","name":"New Orleans / Dixieland","years":"1910s–1920s","keywords":"集体即兴 · 铜管 · 热爵士","desc":"在新奥尔良的街头与酒馆里，铜管、单簧管与节奏组围成一圈集体即兴，爵士第一次成为‘一起说话’的音乐。路易斯·阿姆斯特朗在此把独奏推上历史舞台。"},{"key":"swing","name":"Swing / Big Band","years":"1930s–1940s","keywords":"舞曲 · 大乐队 · 编曲","desc":"摇摆时代是爵士最流行的黄金期。大乐队、编曲与舞池让爵士成为全民流行乐，艾灵顿与贝西把黑人乐队的声音变成美国的声音。"},{"key":"bebop","name":"Bebop","years":"1940s–1950s","keywords":"高速 · 复杂和声 · 炫技","desc":"比波普把爵士从舞厅夺回到夜店与音乐家手中。小组合、极快的速度、复杂的和声替换，让爵士第一次明确成为‘听’的艺术而非‘跳’的伴奏。"},{"key":"cool","name":"Cool Jazz / West Coast","years":"1950s","keywords":"克制 · 清爽 · 室内乐感","desc":"对比波普的火热，冷爵士选择克制与编曲，吸收古典室内乐的质感。声音变轻、变慢、变得有空间，西海岸阳光下的爵士显得格外干净。"},{"key":"hardbop","name":"Hard Bop / Soul Jazz","years":"1950s–1960s","keywords":"蓝调 · 福音 · 强律动","desc":"硬波普把蓝调、福音和 R&B 的体温带回比波普。强烈的律动、教堂式的呼应、城市黑人的生活经验，让这一支成为最‘好听’也最有根的爵士。"},{"key":"modal","name":"Modal Jazz","years":"1958–1960s","keywords":"调式 · 少和弦 · 长线条","desc":"调式爵士不再围着快速变化的和弦转，而是把一两个调式拉长，给独奏更大的呼吸空间。《Kind of Blue》是它的圣经，也是史上最畅销的爵士唱片。"},{"key":"free","name":"Free Jazz / Avant-garde","years":"1960s–1970s","keywords":"无固定和声 · 集体即兴 · 声音实验","desc":"自由爵士拆掉了和声与节拍的框架，把音乐还原为纯粹的声音与情绪。它常被误解为噪音，却是民权年代最激烈、最诚实的黑人艺术宣言。"},{"key":"latin","name":"Latin Jazz / Bossa Nova","years":"1950s–1970s","keywords":"古巴 · 巴西 · 非洲节奏","desc":"当爵士遇上古巴的克拉维节奏与巴西的波萨诺瓦，便有了拉丁爵士。它把非洲的根重新接回美洲音乐，让摇摆多出一层热带的摆动。"},{"key":"fusion","name":"Fusion / Jazz-rock","years":"1970s–1980s","keywords":"电声 · 摇滚 · 放克 · 合成器","desc":"融合爵士插上电:电钢、合成器、放克贝斯与摇滚鼓点。迈尔斯的《Bitches Brew》打开闸门，爵士与摇滚、放克在能量与音量上正面相遇。"},{"key":"neobop","name":"Neo-bop / Straight-ahead","years":"1980s–1990s","keywords":"回归传统 · 学院化 · 现代硬波普","desc":"在融合与流行之后，温顿·马萨利斯一代回到原声、回到传统,把爵士史变成可以学习、演奏与传承的经典。学院化让爵士活了下来，也引发关于‘活力’的争论。"},{"key":"acid","name":"Acid / Nu / Smooth Jazz","years":"1990s–2010s","keywords":"舞曲 · 电子 · R&B · 都市感","desc":"酸爵士与新爵士把采样、浩室、嘻哈和 R&B 接进爵士,让它重新出现在俱乐部与都市夜晚。Blue Note 的老唱片在这里被重新切片成新的节拍。"},{"key":"newlondon","name":"New London / Global Revival","years":"2010s–2020s","keywords":"全球化 · 嘻哈 · 新灵性","desc":"新一代爵士在伦敦、洛杉矶与全球开花,接上嘻哈、非洲节奏与精神性追寻。卡马西、莎芭卡们让爵士重新成为年轻人、舞池与抗争的音乐。"}];
